export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const k = cellKey(x + dx, y + dy);
      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
    }
  }

  const survivors: Cell[] = cells.filter(([x, y]) => {
    const count = neighborCounts.get(cellKey(x, y)) ?? 0;
    return count === 2 || count === 3;
  });

  const births: Cell[] = [];
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = cellKey(nx, ny);
      if (liveSet.has(k)) continue;
      if (neighborCounts.get(k) !== 3) continue;
      if (births.some(([bx, by]) => bx === nx && by === ny)) continue;
      births.push([nx, ny]);
    }
  }

  return [...survivors, ...births];
}

